-- ============================================================
--  KCN QUANG HƯNG — HẢI PHÒNG
--  CSDL KHÔNG GIAN VỚI POSTGRESQL + POSTGIS
--  Dữ liệu: Bãi rác, Tòa nhà, Đường, Ranh giới KCN
--  Tác giả: [Sinh viên]  |  Ngày: 2025
--  EPSG: 4326 (WGS84)
-- ============================================================


-- ════════════════════════════════════════════════════
--  PHẦN 1: CÀI ĐẶT & KHỞI TẠO
-- ════════════════════════════════════════════════════

-- 1.1 Tạo CSDL
CREATE DATABASE quangHungGIS
    ENCODING = 'UTF8'
    LC_COLLATE = 'vi_VN.UTF-8'
    TEMPLATE = template0;

\c quangHungGIS;

-- 1.2 Bật extension PostGIS
CREATE EXTENSION IF NOT EXISTS postgis;
CREATE EXTENSION IF NOT EXISTS postgis_topology;
CREATE EXTENSION IF NOT EXISTS fuzzystrmatch;
CREATE EXTENSION IF NOT EXISTS postgis_tiger_geocoder;

-- Kiểm tra phiên bản
SELECT postgis_full_version();


-- ════════════════════════════════════════════════════
--  PHẦN 2: TẠO BẢNG (DDL)
-- ════════════════════════════════════════════════════

-- 2.1 Bảng ranh giới KCN
CREATE TABLE kcn_bounds (
    id          SERIAL PRIMARY KEY,
    ten_kcn     VARCHAR(200) DEFAULT 'KCN Quang Hưng',
    tinh_thanh  VARCHAR(100) DEFAULT 'Hải Phòng',
    dien_tich   FLOAT,           -- m²
    nam_thanhlap INT,
    ghi_chu     TEXT,
    geom        GEOMETRY(Polygon, 4326) NOT NULL
);

-- 2.2 Bảng tòa nhà
CREATE TABLE buildings (
    id          SERIAL PRIMARY KEY,
    nature      VARCHAR(50)  NOT NULL  -- 'Industrial' | 'Residential'
                CHECK (nature IN ('Industrial', 'Residential')),
    company     VARCHAR(10),
    tang_cao    INT DEFAULT 1,
    nam_xay     INT,
    trang_thai  VARCHAR(20) DEFAULT 'Đang sử dụng',
    geom        GEOMETRY(Polygon, 4326) NOT NULL
);

-- 2.3 Bảng đường giao thông
CREATE TABLE roads (
    id          SERIAL PRIMARY KEY,
    ten_duong   VARCHAR(100),
    nb_lanes    INT DEFAULT 2,
    loai_duong  VARCHAR(50) DEFAULT 'Nội bộ KCN',
    chat_lieu   VARCHAR(50) DEFAULT 'Bê tông nhựa',
    chieu_dai   FLOAT,           -- m (tính tự động)
    geom        GEOMETRY(LineString, 4326) NOT NULL
);

-- 2.4 Bảng bãi rác
CREATE TABLE garbage (
    id          SERIAL PRIMARY KEY,
    ten         VARCHAR(200),
    loai_chat_thai VARCHAR(100),
    muc_doc_hai VARCHAR(20)  DEFAULT 'Cao'
                CHECK (muc_doc_hai IN ('Thấp', 'Trung bình', 'Cao', 'Rất cao')),
    dien_tich   FLOAT,           -- m²
    nam_phat_hien INT DEFAULT 2016,
    ghi_chu     TEXT,
    geom        GEOMETRY(Point, 4326) NOT NULL
);

-- 2.5 Bảng vùng đệm (lưu kết quả truy vấn)
CREATE TABLE garbage_buffers (
    id              SERIAL PRIMARY KEY,
    garbage_id      INT REFERENCES garbage(id),
    ban_kinh_m      FLOAT NOT NULL,
    ngay_tao        TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    geom            GEOMETRY(Polygon, 4326)
);

-- 2.6 Bảng log truy vấn không gian
CREATE TABLE spatial_query_log (
    id          SERIAL PRIMARY KEY,
    ten_truy_van VARCHAR(100),
    mo_ta       TEXT,
    sql_text    TEXT,
    so_ket_qua  INT,
    thoi_gian   TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);


-- ════════════════════════════════════════════════════
--  PHẦN 3: IMPORT DỮ LIỆU TỪ SHAPEFILE
-- ════════════════════════════════════════════════════

-- 3.1 Dùng shp2pgsql (chạy trong terminal, không phải psql)
-- shp2pgsql -I -s 3405 -W "UTF-8" includes/garbadge.shp public.garbage_shp | psql -U postgres -d quangHungGIS
-- shp2pgsql -I -s 3405 -W "UTF-8" includes/building.shp public.building_shp | psql -U postgres -d quangHungGIS
-- shp2pgsql -I -s 3405 -W "UTF-8" includes/road.shp     public.road_shp     | psql -U postgres -d quangHungGIS
-- shp2pgsql -I -s 3405 -W "UTF-8" includes/bounds.shp   public.bounds_shp   | psql -U postgres -d quangHungGIS

-- 3.2 Chuyển hệ tọa độ VN-2000 (EPSG:3405) → WGS84 (EPSG:4326)
-- Sau khi import, insert vào bảng chính với ST_Transform:
-- INSERT INTO garbage (ten, loai_chat_thai, geom)
-- SELECT 'Bãi rác ' || gid, 'Chất thải công nghiệp',
--        ST_Transform(geom, 4326)
-- FROM garbage_shp;


-- ════════════════════════════════════════════════════
--  PHẦN 4: NHẬP DỮ LIỆU TRỰC TIẾP (WGS84)
-- ════════════════════════════════════════════════════

-- 4.1 Ranh giới KCN
INSERT INTO kcn_bounds (ten_kcn, tinh_thanh, nam_thanhlap, geom) VALUES
('KCN Quang Hưng', 'Hải Phòng', 2005,
 ST_GeomFromText('POLYGON((106.60788973 20.82758652,106.60788973 20.83642643,106.61611510 20.83642643,106.61611510 20.82758652,106.60788973 20.82758652))', 4326));

-- Cập nhật diện tích tự động (m²)
UPDATE kcn_bounds
SET dien_tich = ST_Area(geom::geography)
WHERE dien_tich IS NULL;

