(106,2,ST_GeomFromText('LINESTRING(106.61266127 20.83220032,106.61268722 20.83211858,106.61270548 20.83203683,106.61271990 20.83195059,106.61272278 20.83186615,106.61271221 20.83176734,106.61268722 20.83165146,106.61260360 20.83141610)',4326)),
