(109,2,ST_GeomFromText('LINESTRING(106.61132720 20.83122206,106.61135123 20.83120769,106.61138391 20.83118523,106.61139448 20.83116637,106.61140217 20.83114660,106.61140025 20.83112235,106.61138295 20.83108552)',4326)),
