-- Tính chiều dài tự động
UPDATE roads
SET chieu_dai = ST_Length(geom::geography)
WHERE chieu_dai IS NULL;


-- ════════════════════════════════════════════════════
--  PHẦN 5: TẠO INDEX KHÔNG GIAN
-- ════════════════════════════════════════════════════

-- Index GiST cho tất cả cột geometry
CREATE INDEX idx_buildings_geom   ON buildings   USING GIST (geom);
CREATE INDEX idx_roads_geom        ON roads        USING GIST (geom);
CREATE INDEX idx_garbage_geom      ON garbage      USING GIST (geom);
CREATE INDEX idx_kcn_bounds_geom   ON kcn_bounds   USING GIST (geom);
CREATE INDEX idx_buffers_geom      ON garbage_buffers USING GIST (geom);

-- Index thường cho các cột tìm kiếm
CREATE INDEX idx_buildings_nature  ON buildings (nature);
CREATE INDEX idx_buildings_company ON buildings (company);
CREATE INDEX idx_roads_lanes       ON roads (nb_lanes);
CREATE INDEX idx_garbage_mucdo     ON garbage (muc_doc_hai);

-- Cập nhật thống kê
ANALYZE buildings;
ANALYZE roads;
ANALYZE garbage;
ANALYZE kcn_bounds;


-- ════════════════════════════════════════════════════
--  PHẦN 6: VIEWS HỮU ÍCH
-- ════════════════════════════════════════════════════

-- View: Tổng quan KCN
CREATE OR REPLACE VIEW v_kcn_summary AS
SELECT
    'Bãi rác'         AS doi_tuong,
    COUNT(*)          AS so_luong,
    NULL::FLOAT       AS tong_dien_tich_m2
FROM garbage
UNION ALL
SELECT
    'Tòa nhà (' || nature || ')' AS doi_tuong,
    COUNT(*),
    SUM(ST_Area(geom::geography)) AS tong_dien_tich_m2
FROM buildings
GROUP BY nature
UNION ALL
SELECT
    'Đường giao thông',
    COUNT(*),
    SUM(ST_Length(geom::geography)) AS chieu_dai_tong_m
FROM roads;

-- View: Bãi rác kèm thông tin vùng lân cận
CREATE OR REPLACE VIEW v_garbage_risk AS
SELECT
    g.id,
    g.ten,
    g.muc_doc_hai,
    ST_X(g.geom) AS longitude,
    ST_Y(g.geom) AS latitude,
    (SELECT COUNT(*) FROM buildings b
     WHERE ST_DWithin(g.geom::geography, b.geom::geography, 100)
    ) AS so_toa_nha_100m,
    (SELECT COUNT(*) FROM roads r
     WHERE ST_DWithin(g.geom::geography, r.geom::geography, 50)
    ) AS so_duong_50m
FROM garbage g;

-- View: Tòa nhà trong vùng nguy hiểm
CREATE OR REPLACE VIEW v_buildings_in_danger AS
SELECT
    b.id,
    b.nature,
    b.company,
    MIN(ST_Distance(b.geom::geography, g.geom::geography)) AS khoang_cach_bai_rac_m,
    COUNT(g.id) AS so_bai_rac_lien_quan
FROM buildings b
JOIN garbage g
    ON ST_DWithin(b.geom::geography, g.geom::geography, 200)
GROUP BY b.id, b.nature, b.company
ORDER BY khoang_cach_bai_rac_m;


-- ════════════════════════════════════════════════════
--  PHẦN 7: TRUY VẤN KHÔNG GIAN (SPATIAL QUERIES)
-- ════════════════════════════════════════════════════

-- ─────────────────────────────────────────────
-- 7.1  ST_Distance — Khoảng cách bãi rác ↔ tòa nhà
-- ─────────────────────────────────────────────
-- Tìm 5 tòa nhà gần mỗi bãi rác nhất
SELECT
    g.id            AS garbage_id,
    g.ten           AS bai_rac,
    b.id            AS building_id,
    b.nature        AS loai_toa_nha,
    b.company       AS cong_ty,
    ROUND(ST_Distance(
        g.geom::geography,
        b.geom::geography
    )::NUMERIC, 2)  AS khoang_cach_m
FROM garbage g
CROSS JOIN LATERAL (
    SELECT b2.id, b2.nature, b2.company, b2.geom
    FROM buildings b2
    ORDER BY g.geom <-> b2.geom   -- sử dụng index KNN
    LIMIT 3
) b
ORDER BY g.id, khoang_cach_m;


-- ─────────────────────────────────────────────
-- 7.2  ST_Buffer — Tạo vùng đệm 50m, 100m, 200m
-- ─────────────────────────────────────────────
-- Hiển thị vùng đệm nhiều mức
SELECT
    id,
    ten,
    ST_Buffer(geom::geography, 50 )::geometry  AS buffer_50m,
    ST_Buffer(geom::geography, 100)::geometry  AS buffer_100m,
    ST_Buffer(geom::geography, 200)::geometry  AS buffer_200m
FROM garbage;

-- Lưu vùng đệm 50m vào bảng
INSERT INTO garbage_buffers (garbage_id, ban_kinh_m, geom)
SELECT
    id,
    50,
    ST_Buffer(geom::geography, 50)::geometry
FROM garbage;


-- ─────────────────────────────────────────────
-- 7.3  ST_Intersects — Tòa nhà trong vùng đệm
-- ─────────────────────────────────────────────
SELECT DISTINCT
    b.id,
    b.nature,
    b.company,
    g.ten           AS bai_rac_lien_quan,
    ROUND(ST_Distance(
        b.geom::geography,
        g.geom::geography
    )::NUMERIC, 1)  AS khoang_cach_m
FROM buildings b
JOIN (
    SELECT id, ten,
           ST_Buffer(geom::geography, 50)::geometry AS buf
    FROM garbage
) g ON ST_Intersects(b.geom, g.buf)
ORDER BY khoang_cach_m;


-- ─────────────────────────────────────────────
-- 7.4  ST_Within — Đối tượng nằm hoàn toàn trong KCN
-- ─────────────────────────────────────────────
-- Tòa nhà trong ranh giới KCN
SELECT b.id, b.nature, b.company
FROM buildings b, kcn_bounds k
WHERE ST_Within(b.geom, k.geom);

-- Bãi rác trong ranh giới KCN
SELECT g.id, g.ten, g.muc_doc_hai
FROM garbage g, kcn_bounds k
WHERE ST_Within(g.geom, k.geom);


-- ─────────────────────────────────────────────
-- 7.5  ST_Contains / ST_Covers
-- ─────────────────────────────────────────────
-- KCN chứa bao nhiêu tòa nhà?
SELECT
    k.ten_kcn,
    COUNT(b.id)     AS so_toa_nha_ben_trong
FROM kcn_bounds k
LEFT JOIN buildings b ON ST_Contains(k.geom, b.geom)
GROUP BY k.id, k.ten_kcn;


-- ─────────────────────────────────────────────
-- 7.6  ST_DWithin — Tìm trong bán kính (dùng index)
-- ─────────────────────────────────────────────
-- Đường giao thông trong 30m kể từ bãi rác (nguy cơ rò rỉ)
SELECT
    g.ten           AS bai_rac,
    r.id            AS road_id,
    r.nb_lanes,
    ROUND(ST_Distance(
        g.geom::geography,
        r.geom::geography
    )::NUMERIC, 1)  AS khoang_cach_m
FROM garbage g
JOIN roads r
    ON ST_DWithin(g.geom::geography, r.geom::geography, 30)
ORDER BY g.id, khoang_cach_m;


-- ─────────────────────────────────────────────
-- 7.7  ST_ConvexHull + ST_Collect — Bao lồi
-- ─────────────────────────────────────────────
SELECT
    ST_ConvexHull(
        ST_Collect(geom)
    ) AS convex_hull_bai_rac,
    ST_Area(
        ST_ConvexHull(ST_Collect(geom))::geography
    ) AS dien_tich_m2
FROM garbage;


-- ─────────────────────────────────────────────
-- 7.8  ST_Union — Gộp vùng đệm chồng lên nhau
-- ─────────────────────────────────────────────
SELECT
    ST_Union(buf) AS merged_buffer,
    COUNT(*)      AS so_bai_rac,
    ROUND(ST_Area(ST_Union(buf)::geography)::NUMERIC, 2) AS tong_dien_tich_m2
FROM (
    SELECT ST_Buffer(geom::geography, 50)::geometry AS buf
    FROM garbage
) sub;


-- ─────────────────────────────────────────────
-- 7.9  ST_Length — Tổng chiều dài đường
-- ─────────────────────────────────────────────
SELECT
    nb_lanes,
    COUNT(*)                            AS so_doan,
    ROUND(SUM(ST_Length(geom::geography))::NUMERIC, 2) AS tong_chieu_dai_m,
    ROUND(AVG(ST_Length(geom::geography))::NUMERIC, 2) AS tb_chieu_dai_m
FROM roads
GROUP BY nb_lanes
ORDER BY nb_lanes;


-- ─────────────────────────────────────────────
-- 7.10  ST_Area — Thống kê diện tích tòa nhà
-- ─────────────────────────────────────────────
SELECT
    nature                  AS loai_toa_nha,
    COUNT(*)                AS so_luong,
    ROUND(SUM(ST_Area(geom::geography))::NUMERIC, 2)  AS tong_dien_tich_m2,
    ROUND(AVG(ST_Area(geom::geography))::NUMERIC, 2)  AS tb_dien_tich_m2,
    ROUND(MIN(ST_Area(geom::geography))::NUMERIC, 2)  AS min_dien_tich_m2,
    ROUND(MAX(ST_Area(geom::geography))::NUMERIC, 2)  AS max_dien_tich_m2
FROM buildings
GROUP BY nature;


-- ─────────────────────────────────────────────
-- 7.11  ST_Centroid — Tọa độ tâm tòa nhà
-- ─────────────────────────────────────────────
SELECT
    id,
    nature,
    company,
    ROUND(ST_X(ST_Centroid(geom))::NUMERIC, 6) AS lon,
    ROUND(ST_Y(ST_Centroid(geom))::NUMERIC, 6) AS lat
FROM buildings
LIMIT 20;


-- ─────────────────────────────────────────────
-- 7.12  ST_Intersection — Phần giao của 2 đối tượng
-- ─────────────────────────────────────────────
-- Phần giao giữa vùng đệm 100m bãi rác và ranh giới KCN
SELECT
    g.id,
    g.ten,
    ST_Intersection(
        ST_Buffer(g.geom::geography, 100)::geometry,
        k.geom
    ) AS intersection_geom,
    ST_Area(
        ST_Intersection(
            ST_Buffer(g.geom::geography, 100)::geometry,
            k.geom
        )::geography
    ) AS dien_tich_giao_m2
FROM garbage g
CROSS JOIN kcn_bounds k
WHERE ST_Intersects(
    ST_Buffer(g.geom::geography, 100)::geometry,
    k.geom
);


-- ─────────────────────────────────────────────
-- 7.13  ST_Difference — Phần không gian còn lại
-- ─────────────────────────────────────────────
-- Vùng KCN không bị ảnh hưởng bởi bãi rác (ngoài buffer 100m)
SELECT
    k.ten_kcn,
    ST_Difference(
        k.geom,
        (SELECT ST_Union(ST_Buffer(geom::geography, 100)::geometry)
         FROM garbage)
    ) AS vung_an_toan,
    ROUND(
        ST_Area(ST_Difference(
            k.geom,
            (SELECT ST_Union(ST_Buffer(geom::geography, 100)::geometry) FROM garbage)
        )::geography)::NUMERIC, 2
    ) AS dien_tich_an_toan_m2
FROM kcn_bounds k;


-- ─────────────────────────────────────────────
-- 7.14  Nearest Neighbor với KNN (<->)
-- ─────────────────────────────────────────────
-- Tìm bãi rác gần nhất với mỗi tòa nhà công nghiệp
SELECT
    b.id            AS building_id,
    b.company,
    g.id            AS nearest_garbage_id,
    g.ten           AS ten_bai_rac,
    ROUND(ST_Distance(
        b.geom::geography,
        g.geom::geography
    )::NUMERIC, 2)  AS khoang_cach_m
FROM buildings b
CROSS JOIN LATERAL (
    SELECT g2.id, g2.ten, g2.geom
    FROM garbage g2
    ORDER BY b.geom <-> g2.geom
    LIMIT 1
) g
WHERE b.nature = 'Industrial'
ORDER BY khoang_cach_m;


-- ─────────────────────────────────────────────
-- 7.15  Spatial JOIN tổng hợp: báo cáo đầy đủ
-- ─────────────────────────────────────────────
SELECT
    g.id                                        AS garbage_id,
    g.ten                                       AS bai_rac,
    g.muc_doc_hai,
    ROUND(ST_X(g.geom)::NUMERIC, 5)            AS longitude,
    ROUND(ST_Y(g.geom)::NUMERIC, 5)            AS latitude,
    COUNT(DISTINCT b.id)                        AS so_toa_nha_50m,
    COUNT(DISTINCT CASE WHEN b.nature='Industrial' THEN b.id END) AS cong_nghiep_50m,
    COUNT(DISTINCT CASE WHEN b.nature='Residential' THEN b.id END) AS dan_cu_50m,
    COUNT(DISTINCT r.id)                        AS so_duong_30m,
    ROUND(MIN(ST_Distance(g.geom::geography, b.geom::geography))::NUMERIC, 1) AS khoang_cach_toa_nha_gan_nhat_m
FROM garbage g
LEFT JOIN buildings b
    ON ST_DWithin(g.geom::geography, b.geom::geography, 50)
LEFT JOIN roads r
    ON ST_DWithin(g.geom::geography, r.geom::geography, 30)
GROUP BY g.id, g.ten, g.muc_doc_hai, g.geom
ORDER BY so_toa_nha_50m DESC;


-- ─────────────────────────────────────────────
-- 7.16  Phân tích cụm (clustering) bãi rác
-- ─────────────────────────────────────────────
-- Nhóm các bãi rác cách nhau ≤ 200m thành 1 cụm
WITH clusters AS (
    SELECT
        g1.id,
        g1.ten,
        COUNT(g2.id) - 1            AS so_bai_rac_trong_cum,
        ARRAY_AGG(g2.id ORDER BY g2.id) AS cum_ids
    FROM garbage g1
    JOIN garbage g2
        ON ST_DWithin(g1.geom::geography, g2.geom::geography, 200)
    GROUP BY g1.id, g1.ten
)
SELECT
    id,
    ten,
    so_bai_rac_trong_cum,
    cum_ids,
    CASE
        WHEN so_bai_rac_trong_cum = 0 THEN 'Đơn lẻ'
        WHEN so_bai_rac_trong_cum BETWEEN 1 AND 3 THEN 'Cụm nhỏ'
        ELSE 'Cụm lớn — NGUY HIỂM CAO'
    END AS phan_loai_cum
FROM clusters
ORDER BY so_bai_rac_trong_cum DESC;


-- ════════════════════════════════════════════════════
--  PHẦN 8: EXPORT KẾT QUẢ
-- ════════════════════════════════════════════════════

-- Export GeoJSON (dùng trên web / Leaflet)
SELECT json_build_object(
    'type',     'FeatureCollection',
    'features', json_agg(
        json_build_object(
            'type',       'Feature',
            'geometry',   ST_AsGeoJSON(geom)::json,
            'properties', json_build_object(
                'id',           id,
                'ten',          ten,
                'loai',         loai_chat_thai,
                'muc_doc_hai',  muc_doc_hai
            )
        )
    )
) AS geojson
FROM garbage;

-- Export KML
SELECT ST_AsKML(geom) FROM garbage;

-- Export WKT
SELECT id, ten, ST_AsText(geom) AS wkt FROM garbage;

-- Export với hệ tọa độ khác (VN2000 → WGS84)
SELECT id,
    ST_AsGeoJSON(ST_Transform(geom, 4326)) AS geojson_wgs84
FROM garbage;


-- ════════════════════════════════════════════════════
--  PHẦN 9: MAINTENANCE & UTILS
-- ════════════════════════════════════════════════════

-- Kiểm tra tính hợp lệ của geometry
SELECT id, ten,
    ST_IsValid(geom)        AS is_valid,
    ST_IsSimple(geom)       AS is_simple,
    ST_GeometryType(geom)   AS geom_type,
    ST_SRID(geom)           AS srid
FROM garbage;

-- Sửa geometry không hợp lệ
UPDATE buildings
SET geom = ST_MakeValid(geom)
WHERE NOT ST_IsValid(geom);

-- Thông tin SRID
SELECT srid, auth_name, auth_srid, srtext
FROM spatial_ref_sys
WHERE srid IN (4326, 3405, 32648);

-- Kích thước bảng
SELECT
    schemaname,
    tablename,
    pg_size_pretty(pg_total_relation_size(schemaname||'.'||tablename)) AS size
FROM pg_tables
WHERE schemaname = 'public'
ORDER BY pg_total_relation_size(schemaname||'.'||tablename) DESC;

-- Danh sách layer (geometry_columns)
SELECT f_table_name, f_geometry_column, type, srid
FROM geometry_columns
WHERE f_table_schema = 'public';


-- ════════════════════════════════════════════════════
--  KẾT THÚC SCRIPT
-- ════════════════════════════════════════════════════
-- Tổng kết:
--   ✓ 16 truy vấn không gian PostGIS
--   ✓ 5 bảng với GIST index
--   ✓ 3 views phân tích
--   ✓ Import từ shapefile + WGS84
--   ✓ Export GeoJSON / KML / WKT
-- ════════════════════════════════════════════════════
